    var currentTransform = el.style.transform || '';
    var initialTransforms = [];
    var regex = /(w+)(([^)]+))/g;
    var match;
    
    while ((match = regex.exec(currentTransform)) !== null) {
      var funcName = match[1];
      var funcValue = match[2];
      
      // Skip translate - we'll manage it separately
      if (funcName !== 'translate') {
        initialTransforms.push(funcName + '(' + funcValue + ')');
      }
    }

